import React, { useState } from 'react';
import './UsersCatalog.css';

const UsersCatalog = () => {
  const [users] = useState([
    {
      id: 1,
      username: 'DarkLord',
      level: 5,
      points: 12500,
      joined: '15 янв 2023',
      lastActive: '2 часа назад',
      avatar: null,
      badges: ['Топ читатель', 'Активный пользователь', 'Коллекционер']
    },
    {
      id: 2,
      username: 'MangaMaster',
      level: 5,
      points: 9800,
      joined: '20 фев 2023',
      lastActive: '5 часов назад',
      avatar: null,
      badges: ['Эксперт', 'Рецензент', 'Помощник']
    },
    {
      id: 3,
      username: 'WeebQueen',
      level: 4,
      points: 7200,
      joined: '10 мар 2023',
      lastActive: '1 день назад',
      avatar: null,
      badges: ['Любитель манги', 'Активный комментатор']
    },
    {
      id: 4,
      username: 'AnimeLover',
      level: 4,
      points: 6500,
      joined: '25 мар 2023',
      lastActive: '2 дня назад',
      avatar: null,
      badges: ['Фанат аниме', 'Коллекционер']
    },
    {
      id: 5,
      username: 'KawaiiChan',
      level: 3,
      points: 4200,
      joined: '5 апр 2023',
      lastActive: '3 часа назад',
      avatar: null,
      badges: ['Новичок месяца']
    },
    {
      id: 6,
      username: 'OtakuKing',
      level: 3,
      points: 3800,
      joined: '15 апр 2023',
      lastActive: '1 час назад',
      avatar: null,
      badges: ['Активный читатель']
    },
    {
      id: 7,
      username: 'Senpai',
      level: 2,
      points: 1500,
      joined: '1 май 2023',
      lastActive: '6 часов назад',
      avatar: null,
      badges: ['Новый пользователь']
    },
    {
      id: 8,
      username: 'MangaAddict',
      level: 2,
      points: 1200,
      joined: '10 май 2023',
      lastActive: '12 часов назад',
      avatar: null,
      badges: ['Активный']
    }
  ]);

  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('level');
  const [currentPage, setCurrentPage] = useState(1);
  const usersPerPage = 6;

  const filteredUsers = users.filter(user =>
    user.username.toLowerCase().includes(searchTerm.toLowerCase())
  ).sort((a, b) => {
    switch (sortBy) {
      case 'level':
        return b.level - a.level || b.points - a.points;
      case 'points':
        return b.points - a.points;
      case 'newest':
        return new Date(b.joined) - new Date(a.joined);
      case 'active':
        return a.lastActive.localeCompare(b.lastActive);
      default:
        return b.level - a.level;
    }
  });

  const indexOfLastUser = currentPage * usersPerPage;
  const indexOfFirstUser = indexOfLastUser - usersPerPage;
  const currentUsers = filteredUsers.slice(indexOfFirstUser, indexOfLastUser);
  const totalPages = Math.ceil(filteredUsers.length / usersPerPage);

  return (
    <div className="users-catalog">
      <div className="catalog-header">
        <h2>Каталог пользователей</h2>
        
        <div className="catalog-controls">
          <div className="search-box">
            <i className="fas fa-search"></i>
            <input
              type="text"
              placeholder="Поиск пользователей..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          
          <div className="sort-controls">
            <select 
              value={sortBy} 
              onChange={(e) => setSortBy(e.target.value)}
              className="sort-select"
            >
              <option value="level">По уровню</option>
              <option value="points">По очкам</option>
              <option value="newest">Сначала новые</option>
              <option value="active">По активности</option>
            </select>
          </div>
        </div>
      </div>
      
      <div className="users-grid">
        {currentUsers.map(user => (
          <div key={user.id} className="user-card">
            <div className="user-header">
              <div className="user-avatar">
                {user.avatar ? (
                  <img src={user.avatar} alt={user.username} />
                ) : (
                  <i className="fas fa-user"></i>
                )}
              </div>
              
              <div className="user-info">
                <h3 className="username">{user.username}</h3>
                <div className="user-level">
                  <span className="level-badge">Уровень {user.level}</span>
                  <span className="user-points">{user.points} очков</span>
                </div>
              </div>
            </div>
            
            <div className="user-stats">
              <div className="stat">
                <span className="stat-label">На сайте с</span>
                <span className="stat-value">{user.joined}</span>
              </div>
              <div className="stat">
                <span className="stat-label">Был в сети</span>
                <span className="stat-value">{user.lastActive}</span>
              </div>
            </div>
            
            <div className="user-badges">
              <h4>Значки:</h4>
              <div className="badges-list">
                {user.badges.map((badge, index) => (
                  <span key={index} className="badge">
                    {badge}
                  </span>
                ))}
              </div>
            </div>
            
            <div className="user-actions">
              <button className="action-btn profile">
                <i className="fas fa-user"></i>
                Профиль
              </button>
              <button className="action-btn message">
                <i className="fas fa-envelope"></i>
                Написать
              </button>
            </div>
          </div>
        ))}
      </div>
      
      <div className="catalog-pagination">
        <button 
          className="pagination-btn" 
          onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
          disabled={currentPage === 1}
        >
          <i className="fas fa-chevron-left"></i>
        </button>
        
        {Array.from({ length: totalPages }, (_, i) => i + 1).map(page => (
          <button
            key={page}
            className={`pagination-btn ${currentPage === page ? 'active' : ''}`}
            onClick={() => setCurrentPage(page)}
          >
            {page}
          </button>
        ))}
        
        <button 
          className="pagination-btn" 
          onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
          disabled={currentPage === totalPages}
        >
          <i className="fas fa-chevron-right"></i>
        </button>
      </div>
    </div>
  );
};

export default UsersCatalog;
